class Solution:
    def reorderedPowerOf2(self, n: int) -> bool:
        count = [0] * 10
        for d in str(n):
            count[int(d)] += 1
        for i in range(30):
            temp = [0] * 10
            temp[0] = 1
            num = 1 << i
            for d in str(num):
                temp[int(d)] += 1
            if count == temp:
                return True
        return False

